#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N;
        scanf("%lld", &N);
        int count = 0;
        for (int b = 2; b <= N; b++) {
            if (N >= b && N < 2 * b) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

